mapper.select:
SELECT d.id, d.id_site, d.id_device_type, s.`name` AS site_name, d.devicename, d.field_value_default, dp.unit, DATE_FORMAT(CONVERT_TZ(d.last_updated,"UTC", t.`value`), "%M %d, %Y %H:%i:%s %p") AS last_updated, IFNULL(d.field_value1, 0) AS power_output, a.id_error, a.start_date, a.end_date, e.message, e.error_code, el.`name` AS error_level_name, et.`name` AS error_type_name, dt.image, el.color, el.id AS id_error_level FROM device d LEFT JOIN device_type dt ON dt.id = d.id_device_type LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN alert a ON a.id_device = d.id AND a.`status` = 1 AND a.end_date IS NULL LEFT JOIN error e ON e.id = a.id_error LEFT JOIN error_level el ON el.id = e.id_error_level LEFT JOIN error_type et ON et.id = e.id_error_type LEFT JOIN device_group dg ON dg.id = d.id_device_group LEFT JOIN device_parameters dp ON dp.id_device_group = dg.id AND dp.slug = d.field_value_default
WHERE d.`status` = 1 AND d.is_delete = 0 AND s.`status` = 1 AND s.is_delete = 0 AND s.id_company = #{id_company} GROUP BY d.id
LIMIT ${limit} OFFSET ${offset};
